import { spawn } from "node:child_process";
import { writeFile, readFile } from "node:fs/promises";
import { resolve, dirname } from "node:path";
import { fileURLToPath } from "node:url";
const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const schemaPath = resolve(__dirname, "..", "src", "lib", "api", "contract", "openapi.json");
const outputPath = resolve(__dirname, "..", "src", "lib", "api", "generated.d.ts");

const header =
  "// DO NOT EDIT — generated by `npm run contract:generate` from src/lib/api/contract/openapi.json\n";

async function main() {
  const binDir = resolve(__dirname, "..", "node_modules", ".bin");
  const bin = process.platform === "win32"
    ? resolve(binDir, "openapi-typescript.cmd")
    : resolve(binDir, "openapi-typescript");

  await new Promise((resolvePromise, rejectPromise) => {
    const child = spawn(bin, [
      schemaPath,
      "-o",
      outputPath,
      "--immutable",
      "--export-type",
    ], { shell: process.platform === "win32", stdio: "inherit" });

    child.on("error", rejectPromise);
    child.on("close", (code) => {
      if (code === 0) {
        resolvePromise();
      } else {
        rejectPromise(new Error(`openapi-typescript exited with code ${code}`));
      }
    });
  });

  const generated = await readFile(outputPath, "utf-8");
  await writeFile(outputPath, header + generated, "utf-8");
  console.log(`Generated ${outputPath}`);
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
